    function graphReport(graph) { const errors = []; const nodes = list(graph?.nodes); const types = new Set(["climate", "biome", "road", "river", "dungeon", "wfc", "scatterprefabs", "rules", "custom"]); const ids = new Set(); for (const node of nodes) { if (!safeId(node.id)) errors.push("Every node needs a stable ID."); if (ids.has(node.id)) errors.push(`Duplicate node ${node.id}.`); if (!types.has(String(node.type || "").toLowerCase())) errors.push(`Unsupported node type ${node.type || "empty"}.`); ids.add(node.id); } for (const node of nodes) for (const dependency of list(node.after)) if (!ids.has(dependency)) errors.push(`${node.id} depends on missing ${dependency}.`); const order = []; const visiting = new Set(); const visited = new Set(); const byId = new Map(nodes.map(node => [node.id, node])); const visit = node => { if (visiting.has(node.id)) return errors.push(`Cycle found at ${node.id}.`); if (visited.has(node.id)) return; visiting.add(node.id); for (const dependency of list(node.after)) if (byId.has(dependency)) visit(byId.get(dependency)); visiting.delete(node.id); visited.add(node.id); order.push(node.id); }; for (const node of nodes) visit(node); return { ok: !errors.length, errors, order }; }
